/**
 * Overall sync status for a feature
 */
export interface SyncStatus {
	featureId: string;
	hasLinearIssue: boolean;
	issueKey: string | null;
	issueNeedsSync: boolean;
	lastIssueSync: string | null;
	taskSyncStatus: TaskSyncStatus[];
	duplicateTaskIds: string[];
	missingTasks: string[]; // Tasks in metadata but not in tasks.md
	newTasks: string[]; // Tasks in tasks.md but not in metadata
}

/**
 * Error class for Linear sync operations
 */
export class LinearSyncError extends Error {
	constructor(
		message: string,
		public code: string,
		public details?: unknown,
		public recoverable: boolean = true,
	) {
		super(message);
		this.name = "LinearSyncError";
	}
}

