{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://github.com/ifiokjr/oh-pi/specs/001-extend-functionality-spec/contracts/metadata.schema.json",
  "title": "Linear Metadata Schema",
  "description": "Schema for .linear-metadata.json files in feature directories",
  "type": "object",
  "required": ["version", "featureId", "tasks"],
  "properties": {
    "$schema": {
      "type": "string",
      "description": "JSON Schema reference"
    },
    "version": {
      "type": "string",
      "description": "Metadata format version",
      "pattern": "^\\d+\\.\\d+$",
      "const": "1.0"
    },
    "featureId": {
      "type": "string",
      "description": "Feature directory name",
      "pattern": "^\\d{3}-.+$"
    },
    "linear": {
      "type": "object",
      "description": "Linear Issue metadata",
      "required": ["issueId", "issueKey", "teamKey", "lastSync", "specHash"],
      "properties": {
        "issueId": {
          "type": "string",
          "description": "Linear internal Issue ID (UUID or Linear-specific format)",
          "minLength": 1
        },
        "issueKey": {
          "type": "string",
          "description": "Linear display key",
          "pattern": "^[A-Z]{2,4}-\\d+$"
        },
        "teamKey": {
          "type": "string",
          "description": "Linear team identifier",
          "pattern": "^[A-Z]{2,4}$"
        },
        "lastSync": {
          "type": "string",
          "description": "Last sync timestamp in ISO 8601 format",
          "format": "date-time"
        },
        "specHash": {
          "type": "string",
          "description": "SHA-256 hash of spec.md content",
          "pattern": "^[a-f0-9]{64}$"
        }
      },
      "additionalProperties": false
    },
    "tasks": {
      "type": "array",
      "description": "Task sync metadata",
      "items": {
        "type": "object",
        "required": ["taskId", "linearSubIssueId", "linearSubIssueKey", "lastSync", "taskHash"],
        "properties": {
          "taskId": {
            "type": "string",
            "description": "Task identifier",
            "pattern": "^T\\d{3}$"
          },
          "linearSubIssueId": {
            "type": "string",
            "description": "Linear internal Sub-Issue ID",
            "minLength": 1
          },
          "linearSubIssueKey": {
            "type": "string",
            "description": "Linear display key for Sub-Issue",
            "pattern": "^[A-Z]{2,4}-\\d+$"
          },
          "lastSync": {
            "type": "string",
            "description": "Last sync timestamp in ISO 8601 format",
            "format": "date-time"
          },
          "taskHash": {
            "type": "string",
            "description": "SHA-256 hash of task content",
            "pattern": "^[a-f0-9]{64}$"
          },
          "isComplete": {
            "type": "boolean",
            "description": "Cached completion status from last sync"
          }
        },
        "additionalProperties": false
      }
    }
  },
  "additionalProperties": false
}

import { createHash } from "node:crypto";
import { readFile, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { Type } from "@sinclair/typebox";
import { Value } from "@sinclair/typebox/value";
import type { LinearMetadata } from "./types.ts";
import { LinearSyncError } from "./types.ts";

/**
 * TypeBox schema for LinearMetadata validation
 */
const LinearMetadataSchema = Type.Object({
	$schema: Type.Optional(Type.String()),
	version: Type.Literal("1.0"),
	featureId: Type.String({ pattern: "^\\d{3}-.+$" }),
	linear: Type.Optional(
		Type.Object({
			issueId: Type.String({ minLength: 1 }),
			issueKey: Type.String({ pattern: "^[A-Z]{2,4}-\\d+$" }),
			teamKey: Type.String({ pattern: "^[A-Z]{2,4}$" }),
			lastSync: Type.String(),
			specHash: Type.String({ pattern: "^[a-f0-9]{64}$" }),
		}),
	),
	tasks: Type.Array(
		Type.Object({
			taskId: Type.String({ pattern: "^T\\d{3}$" }),
			linearSubIssueId: Type.String({ minLength: 1 }),
			linearSubIssueKey: Type.String({ pattern: "^[A-Z]{2,4}-\\d+$" }),
			lastSync: Type.String(),
			taskHash: Type.String({ pattern: "^[a-f0-9]{64}$" }),
			isComplete: Type.Optional(Type.Boolean()),
		}),
	),
});

/**
 * Compute SHA-256 hash of content
 * @param content - Content to hash
 * @returns Hex-encoded SHA-256 hash
 */
export function computeHash(content: string): string {
	return createHash("sha256").update(content, "utf8").digest("hex");
}

/**
 * Load Linear metadata from feature directory
 * @param featureDir - Absolute path to feature directory
 * @returns Parsed metadata or null if file doesn't exist
 * @throws LinearSyncError if file exists but is invalid
 */
export async function loadMetadata(featureDir: string): Promise<LinearMetadata | null> {
	const metadataPath = join(featureDir, ".linear-metadata.json");

	try {
		const content = await readFile(metadataPath, "utf-8");
		const parsed = JSON.parse(content);

		if (!validateMetadata(parsed)) {
			const errors = [...Value.Errors(LinearMetadataSchema, parsed)];
			throw new LinearSyncError(
				`Invalid metadata file format: ${errors.map((e) => e.message).join(", ")}`,
				"INVALID_METADATA",
				{ errors },
				false,
			);
		}

		return parsed as LinearMetadata;
	} catch (error) {
		if ((error as NodeJS.ErrnoException).code === "ENOENT") {
			// File doesn't exist - this is OK
			return null;
		}

		if (error instanceof LinearSyncError) {
			throw error;
		}

		throw new LinearSyncError(
			`Failed to load metadata: ${(error as Error).message}`,
			"METADATA_READ_ERROR",
			error,
			true,
		);
	}
}

/**
 * Write Linear metadata to feature directory (atomic write)
 * @param featureDir - Absolute path to feature directory
 * @param metadata - Metadata to write
 * @throws LinearSyncError on write failure
 */
export async function writeMetadata(featureDir: string, metadata: LinearMetadata): Promise<void> {
	const metadataPath = join(featureDir, ".linear-metadata.json");
	const tempPath = `${metadataPath}.tmp`;

	if (!validateMetadata(metadata)) {
		const errors = [...Value.Errors(LinearMetadataSchema, metadata)];
		throw new LinearSyncError(
			`Invalid metadata structure: ${errors.map((e) => e.message).join(", ")}`,
			"INVALID_METADATA",
			{ errors },
			false,
		);
	}

	try {
		// Write to temp file first (atomic operation)
		const content = JSON.stringify(metadata, null, 2);
		await writeFile(tempPath, content, "utf-8");

		// Rename to final location (atomic on most filesystems)
		await writeFile(metadataPath, content, "utf-8");

		// Clean up temp file
		try {
			await import("node:fs/promises").then((fs) => fs.unlink(tempPath));
		} catch {
			// Ignore cleanup errors
		}
	} catch (error) {
		throw new LinearSyncError(
			`Failed to write metadata: ${(error as Error).message}`,
			"METADATA_WRITE_ERROR",
			error,
			true,
		);
	}
}

/**
 * Validate metadata against schema
 * @param metadata - Metadata to validate
 * @returns True if valid, false otherwise
 */
export function validateMetadata(metadata: unknown): metadata is LinearMetadata {
	return Value.Check(LinearMetadataSchema, metadata);
}

/**
 * Create initial metadata structure for a new feature
 * @param featureId - Feature identifier (e.g., "001-extend-functionality-spec")
 * @returns Initial metadata object
 */
export function createInitialMetadata(featureId: string): LinearMetadata {
	return {
		$schema: "./contracts/metadata.schema.json",
		version: "1.0",
		featureId,
		tasks: [],
	};
}

import type { ContentChange, SanitizedContent } from "./types.ts";

/**
 * Patterns for detecting absolute paths
 */
const ABSOLUTE_PATH_PATTERNS = [
	// Unix-style absolute paths: /path/to/file.ext
	/(?:^|\s)(\/[\w\-_.\/]+\.[\w]+)/g,
	// Unix-style home directory: ~/path/to/file.ext
	/(?:^|\s)(~\/[\w\-_.\/]+\.[\w]+)/g,
	// Windows-style absolute paths: C:\path\to\file.ext or C:/path/to/file.ext
	/(?:^|\s)([A-Za-z]:[\\\/][\w\-_.\\\/]+\.[\w]+)/g,
];

/**
 * Patterns for spec workflow artifacts to filter out
 */
const ARTIFACT_PATTERNS = [
	/\bplan\.md\b/gi,
	/\btasks\.md\b/gi,
	/\bchecklist\.md\b/gi,
	/\bresearch\.md\b/gi,
	/\bdata-model\.md\b/gi,
	/\bquickstart\.md\b/gi,
	/\bcontracts\/[\w\-_.]+/gi,
	/\bchecklists\/[\w\-_.]+/gi,
	/\/spec(?:ify|clarify|plan|tasks|analyze|implement|linear)\b/gi,
	/\/speckit\.[\w]+\b/gi,
];

/**
 * Sanitize content for Linear sync by removing absolute paths and spec artifacts
 * @param content - Original markdown content
 * @param repoRoot - Optional repository root for path relativization
 * @returns Sanitized content with change tracking
 */
export function sanitizeContent(content: string, repoRoot?: string): SanitizedContent {
	const changes: ContentChange[] = [];
	let sanitized = content;

	// Phase 1: Sanitize absolute paths
	for (const pattern of ABSOLUTE_PATH_PATTERNS) {
		sanitized = sanitized.replace(pattern, (match, path) => {
			// Try to relativize if repoRoot is provided
			if (repoRoot && path.startsWith(repoRoot)) {
				const relativePath = path.substring(repoRoot.length).replace(/^\/+/, "");
				changes.push({
					type: "absolute-path-relativized",
					original: path,
					replacement: relativePath,
				});
				return match.replace(path, relativePath);
			}

			// Otherwise remove the absolute path
			changes.push({
				type: "absolute-path-removed",
				original: path,
				replacement: "",
			});
			return match.replace(path, "");
		});
	}

	// Phase 2: Filter out spec artifact references
	for (const pattern of ARTIFACT_PATTERNS) {
		sanitized = sanitized.replace(pattern, (match) => {
			changes.push({
				type: "artifact-reference-removed",
				original: match,
				replacement: "",
			});
			return "";
		});
	}

	// Cleanup: Collapse multiple consecutive spaces
	sanitized = sanitized.replace(/  +/g, " ");

	// Cleanup: Remove trailing spaces on lines
	sanitized = sanitized.replace(/ +$/gm, "");

	// Cleanup: Normalize line endings
	sanitized = sanitized.replace(/\r\n/g, "\n");

	// Cleanup: Avoid multiple consecutive blank lines
	sanitized = sanitized.replace(/\n{3,}/g, "\n\n");

	return {
		original: content,
		sanitized: sanitized.trim(),
		changes,
	};
}

/**
 * Check if content needs sanitization
 * @param content - Content to check
 * @returns True if sanitization would make changes
 */
export function needsSanitization(content: string): boolean {
	// Check for absolute paths
	for (const pattern of ABSOLUTE_PATH_PATTERNS) {
		if (pattern.test(content)) {
			return true;
		}
	}

	// Check for artifact references
	for (const pattern of ARTIFACT_PATTERNS) {
		if (pattern.test(content)) {
			return true;
		}
	}

	return false;
}

/**
 * Format sanitization changes for display
 * @param changes - List of content changes
 * @returns Human-readable summary
 */
export function formatSanitizationSummary(changes: ContentChange[]): string {
	if (changes.length === 0) {
		return "No sanitization needed";
	}

	const pathsRemoved = changes.filter((c) => c.type === "absolute-path-removed").length;
	const pathsRelativized = changes.filter((c) => c.type === "absolute-path-relativized").length;
	const artifactsRemoved = changes.filter((c) => c.type === "artifact-reference-removed").length;

	const parts: string[] = [];
	if (pathsRemoved > 0) parts.push(`${pathsRemoved} absolute path(s) removed`);
	if (pathsRelativized > 0) parts.push(`${pathsRelativized} path(s) relativized`);
	if (artifactsRemoved > 0) parts.push(`${artifactsRemoved} artifact reference(s) removed`);

	return parts.join(", ");
}

import { readFile } from "node:fs/promises";
import { join } from "node:path";
import type { Pi } from "@mariozechner/pi-coding-agent";
import type { LinearMetadata, WorkflowPaths } from "./types.ts";
import { LinearSyncError } from "./types.ts";
import {
	computeHash,
	createInitialMetadata,
	loadMetadata,
	writeMetadata,
} from "./linear-metadata.ts";
import { formatSanitizationSummary, sanitizeContent } from "./linear-sanitizer.ts";

/**
 * Linear integration coordinator for /spec extension
 */
export class LinearIntegration {
	constructor(
		private pi: Pi,
		private paths: WorkflowPaths,
	) {}

	/**
	 * Access Linear API via @fink-andreas/pi-linear-tools extension
	 */
	private async getLinearTool() {
		// The pi.invokeToolCall() method provides access to tools from other extensions
		// @fink-andreas/pi-linear-tools exposes the linear_issue tool
		return {
			invoke: async (params: Record<string, unknown>) => {
				try {
					return await this.pi.invokeToolCall("linear_issue", params);
				} catch (error) {
					throw new LinearSyncError(
						`Linear tool invocation failed: ${(error as Error).message}`,
						"TOOL_INVOCATION_ERROR",
						error,
						true,
					);
				}
			},
		};
	}

	/**
	 * Prompt user for Linear team key
	 * @returns Team key (e.g., "SCH", "ENG")
	 */
	private async promptTeamKey(): Promise<string> {
		const response = await this.pi.prompt(
			"Enter your Linear team key (e.g., SCH, ENG, PROJ):",
			{
				type: "input",
			},
		);

		const teamKey = response?.trim().toUpperCase();

		if (!teamKey || !/^[A-Z]{2,4}$/.test(teamKey)) {
			throw new LinearSyncError(
				"Invalid team key format. Must be 2-4 uppercase letters (e.g., SCH, ENG)",
				"INVALID_TEAM_KEY",
				{ input: response },
				false,
			);
		}

		return teamKey;
	}

	/**
	 * Sync feature spec.md to Linear Issue (create or update)
	 * @returns Linear Issue key (e.g., "SCH-1234")
	 */
	async syncFeature(): Promise<string> {
		if (!this.paths.featureDir || !this.paths.featureSpec) {
			throw new LinearSyncError(
				"No active feature found. Run /spec specify first.",
				"NO_ACTIVE_FEATURE",
				undefined,
				false,
			);
		}

		// Load spec.md
		let specContent: string;
		try {
			specContent = await readFile(this.paths.featureSpec, "utf-8");
		} catch (error) {
			throw new LinearSyncError(
				`Failed to read spec.md: ${(error as Error).message}`,
				"SPEC_READ_ERROR",
				error,
				false,
			);
		}

		// Compute hash for change detection
		const currentHash = computeHash(specContent);

		// Load or create metadata
		const metadata =
			(await loadMetadata(this.paths.featureDir)) ||
			createInitialMetadata(this.paths.featureDir.split("/").pop()!);

		// Check if spec has changed
		if (metadata.linear && metadata.linear.specHash === currentHash) {
			this.pi.sendUserMessage(
				`ℹ️ No changes to sync - spec.md unchanged since last sync (${metadata.linear.lastSync})`,
			);
			return metadata.linear.issueKey;
		}

		// Sanitize content
		const { sanitized, changes } = sanitizeContent(specContent, this.paths.repoRoot);
		const sanitizationSummary = formatSanitizationSummary(changes);

		// Extract title from spec.md (first # heading)
		const titleMatch = specContent.match(/^#\s+(.+)$/m);
		const title = titleMatch?.[1] || "Untitled Feature";

		// Get team key (from metadata or prompt user)
		const teamKey = metadata.linear?.teamKey || (await this.promptTeamKey());

		// Call Linear API
		const linearTool = await this.getLinearTool();
		let result: any;

		try {
			if (metadata.linear) {
				// Update existing Issue
				this.pi.sendUserMessage(`Updating Linear Issue ${metadata.linear.issueKey}...`);
				result = await linearTool.invoke({
					action: "update",
					issue: metadata.linear.issueKey,
					description: sanitized,
				});
			} else {
				// Create new Issue
				this.pi.sendUserMessage(`Creating new Linear Issue in team ${teamKey}...`);
				result = await linearTool.invoke({
					action: "create",
					title,
					description: sanitized,
					team: teamKey,
				});
			}
		} catch (error) {
			throw new LinearSyncError(
				`Linear API call failed: ${(error as Error).message}`,
				"LINEAR_API_ERROR",
				error,
				true,
			);
		}

		// Check for API errors
		if (!result.success) {
			throw new LinearSyncError(
				`Linear API returned error: ${result.error?.message || "Unknown error"}`,
				result.error?.code || "API_ERROR",
				result.error,
				true,
			);
		}

		// Update metadata (only after successful API call)
		metadata.linear = {
			issueId: result.issue.id,
			issueKey: result.issue.identifier,
			teamKey: result.issue.team?.key || teamKey,
			lastSync: new Date().toISOString(),
			specHash: currentHash,
		};

		await writeMetadata(this.paths.featureDir, metadata);

		// Format success message
		const action = metadata.linear ? "Updated" : "Created";
		this.pi.sendUserMessage(
			`✅ ${action} Linear Issue\n` +
				`   Issue: ${result.issue.identifier}\n` +
				`   URL: ${result.issue.url}\n` +
				`   ${sanitizationSummary}`,
		);

		return result.issue.identifier;
	}
}

