/**
 * Linear integration coordinator for /spec extension
 */
export class LinearIntegration {
	constructor(
		private pi: Pi,
		private paths: WorkflowPaths,
	) {}

	/**
	 * Access Linear API via @fink-andreas/pi-linear-tools extension
	 */
	private async getLinearTool() {
		// The pi.invokeToolCall() method provides access to tools from other extensions
		// @fink-andreas/pi-linear-tools exposes the linear_issue tool
		return {
			invoke: async (params: Record<string, unknown>) => {
				try {
					return await this.pi.invokeToolCall("linear_issue", params);
				} catch (error) {
					throw new LinearSyncError(
						`Linear tool invocation failed: ${(error as Error).message}`,
						"TOOL_INVOCATION_ERROR",
						error,
						true,
					);
				}
			},
		};
	}

	/**
	 * Prompt user for Linear team key
	 * @returns Team key (e.g., "SCH", "ENG")
	 */
	private async promptTeamKey(): Promise<string> {
		const response = await this.pi.prompt(
			"Enter your Linear team key (e.g., SCH, ENG, PROJ):",
			{
				type: "input",
			},
		);

		const teamKey = response?.trim().toUpperCase();

		if (!teamKey || !/^[A-Z]{2,4}$/.test(teamKey)) {
			throw new LinearSyncError(
				"Invalid team key format. Must be 2-4 uppercase letters (e.g., SCH, ENG)",
				"INVALID_TEAM_KEY",
				{ input: response },
				false,
			);
		}

		return teamKey;
	}

