import { readFile } from "node:fs/promises";
import type { ParsedTask } from "./types.ts";
import { LinearSyncError } from "./types.ts";

/**
 * Parse a single task from markdown content
 * @param taskContent - Markdown content for one task section
 * @returns Parsed task object
 */
export function parseTask(taskContent: string): ParsedTask {
	// Extract task ID and title from header: ## Task T001: Title
	const headerMatch = taskContent.match(/^##\s+Task\s+(T\d{3}):\s+(.+)$/m);
	if (!headerMatch) {
		throw new LinearSyncError(
			"Invalid task format - missing task header",
			"INVALID_TASK_FORMAT",
			{ content: taskContent.substring(0, 100) },
			false,
		);
	}

	const id = headerMatch[1];
	const title = headerMatch[2].trim();

	// Extract completion status from checkbox: - [x] or - [ ]
	const checkboxMatch = taskContent.match(/^-\s+\[([ xX])\]/m);
	const isComplete = checkboxMatch ? checkboxMatch[1].toLowerCase() === "x" : false;

	// Extract description (everything after the header)
	const descriptionStart = taskContent.indexOf("\n", taskContent.indexOf(headerMatch[0]));
	const description = descriptionStart >= 0 ? taskContent.substring(descriptionStart).trim() : "";

	return {
		id,
		title,
		description,
		isComplete,
		rawContent: taskContent,
	};
}

/**
 * Validate task IDs for duplicates
 * @param tasks - Array of parsed tasks
 * @returns Array of duplicate task IDs (empty if none)
 */
export function validateTaskIds(tasks: ParsedTask[]): string[] {
	const seen = new Set<string>();
	const duplicates = new Set<string>();

	for (const task of tasks) {
		if (seen.has(task.id)) {
			duplicates.add(task.id);
		}
		seen.add(task.id);
	}

	return Array.from(duplicates);
}

/**
 * Parse entire tasks.md file into array of tasks
 * @param tasksFilePath - Path to tasks.md file
 * @returns Array of parsed tasks
 * @throws LinearSyncError if file doesn't exist or parsing fails
 */
export async function parseTasks(tasksFilePath: string): Promise<ParsedTask[]> {
	// Read tasks.md
	let content: string;
	try {
		content = await readFile(tasksFilePath, "utf-8");
	} catch (error) {
		throw new LinearSyncError(
			`Failed to read tasks.md: ${(error as Error).message}`,
			"TASKS_READ_ERROR",
			error,
			false,
		);
	}

	// Split into task sections
	// Tasks are separated by "---" or start with "## Task"
	const taskSections: string[] = [];
	const lines = content.split("\n");
	let currentSection: string[] = [];
	let inTaskSection = false;

	for (let i = 0; i < lines.length; i++) {
		const line = lines[i];

		// Check for task header
		if (/^##\s+Task\s+T\d{3}:/.test(line)) {
			// Save previous section if it exists
			if (currentSection.length > 0) {
				taskSections.push(currentSection.join("\n"));
			}
			// Start new section
			currentSection = [line];
			inTaskSection = true;
		} else if (line.trim() === "---" && inTaskSection) {
			// End current section
			if (currentSection.length > 0) {
				taskSections.push(currentSection.join("\n"));
				currentSection = [];
			}
			inTaskSection = false;
		} else if (inTaskSection) {
			// Add line to current section
			currentSection.push(line);
		}
	}

	// Don't forget the last section
	if (currentSection.length > 0) {
		taskSections.push(currentSection.join("\n"));
	}

	// Parse each section
	const tasks: ParsedTask[] = [];
	for (const section of taskSections) {
		if (section.trim()) {
			try {
				tasks.push(parseTask(section));
			} catch (error) {
				// Skip malformed tasks but log them
				console.warn(`Skipping malformed task section: ${error}`);
			}
		}
	}

	// Validate for duplicates
	const duplicates = validateTaskIds(tasks);
	if (duplicates.length > 0) {
		throw new LinearSyncError(
			`Duplicate task IDs detected: ${duplicates.join(", ")}`,
			"DUPLICATE_TASK_IDS",
			{ duplicates },
			false,
		);
	}

	return tasks;
}

/**
 * Find task by ID in array
 * @param tasks - Array of tasks
 * @param taskId - Task ID to find
 * @returns Task or undefined if not found
 */
export function findTaskById(tasks: ParsedTask[], taskId: string): ParsedTask | undefined {
	return tasks.find((t) => t.id === taskId);
}

