import type { LinearTaskMetadata, ParsedTask, SyncStatus, TaskSyncStatus } from "./types.ts";

/**
 * Status transition rules for Linear Issues and Sub-Issues
 */
export const STATUS_TRANSITION_RULES = {
	// For Sub-Issues
	subIssue: {
		onTaskComplete: "Closed - Done",
		onTaskIncomplete: null, // No change
	},

	// For parent Issues
	issue: {
		onFirstTaskComplete: "In Progress",
		onAllTasksComplete: null, // Manual in Linear
		onNoTasksComplete: null, // No change
	},

	// Terminal states that should not be overwritten
	terminalStates: new Set(["completed", "canceled"]),
} as const;

/**
 * Status transition manager for Linear sync operations
 */
export class StatusTransitionManager {
	/**
	 * Check if a Sub-Issue should transition to "Closed - Done"
	 * @param task - Current task from tasks.md
	 * @param metadata - Existing task metadata (if any)
	 * @returns True if status should transition
	 */
	static shouldTransitionSubIssue(task: ParsedTask, metadata?: LinearTaskMetadata): boolean {
		// Transition if:
		// 1. Task is complete now
		// 2. AND either no metadata exists OR previous state was incomplete
		return task.isComplete && (!metadata || metadata.isComplete === false);
	}

	/**
	 * Check if parent Issue should transition to "In Progress"
	 * @param tasks - All current tasks
	 * @param currentIssueState - Current Linear Issue state
	 * @returns True if parent should transition
	 */
	static shouldTransitionParentIssue(
		tasks: ParsedTask[],
		currentIssueState?: { name: string; type: string },
	): boolean {
		// Don't transition if Issue is in terminal state
		if (currentIssueState && STATUS_TRANSITION_RULES.terminalStates.has(currentIssueState.type)) {
			return false;
		}

		// Don't transition if already "In Progress"
		if (currentIssueState?.name === STATUS_TRANSITION_RULES.issue.onFirstTaskComplete) {
			return false;
		}

		// Transition if at least one task is complete
		const anyComplete = tasks.some((t) => t.isComplete);
		return anyComplete;
	}

	/**
	 * Check if a state is terminal (should not be overwritten)
	 * @param stateType - Linear state type
	 * @returns True if terminal
	 */
	static isTerminalState(stateType: string): boolean {
		return STATUS_TRANSITION_RULES.terminalStates.has(stateType);
	}
}

/**
 * Build sync status summary for a feature
 * @param featureId - Feature identifier
 * @param hasLinearIssue - Whether feature has Linear Issue
 * @param issueKey - Linear Issue key (if exists)
 * @param taskSyncStatus - Per-task sync status
 * @returns Sync status object
 */
export function buildSyncStatus(
	featureId: string,
	hasLinearIssue: boolean,
	issueKey: string | null,
	taskSyncStatus: TaskSyncStatus[],
): SyncStatus {
	// Find duplicate task IDs
	const taskIds = taskSyncStatus.map((t) => t.taskId);
	const duplicates = taskIds.filter((id, index) => taskIds.indexOf(id) !== index);

	// Find tasks in metadata but not in tasks.md
	const missingTasks: string[] = []; // TODO: Implement when we have both sources

	// Find tasks in tasks.md but not in metadata
	const newTasks = taskSyncStatus.filter((t) => !t.hasSubIssue).map((t) => t.taskId);

	return {
		featureId,
		hasLinearIssue,
		issueKey,
		issueNeedsSync: false, // Will be set by caller
		lastIssueSync: null, // Will be set by caller
		taskSyncStatus,
		duplicateTaskIds: Array.from(new Set(duplicates)),
		missingTasks,
		newTasks,
	};
}

/**
 * Format sync status for display
 * @param status - Sync status object
 * @returns Formatted string
 */
export function formatSyncStatus(status: SyncStatus): string {
	const lines: string[] = [];

	lines.push(`📊 Linear Sync Status\n`);
	lines.push(`Feature: ${status.featureId}`);

	if (status.hasLinearIssue) {
		lines.push(`├─ Linear Issue: ${status.issueKey}`);
		if (status.lastIssueSync) {
			lines.push(`├─ Last synced: ${status.lastIssueSync}`);
		}
		if (status.issueNeedsSync) {
			lines.push(`└─ Local changes: spec.md has changes (needs sync)`);
		} else {
			lines.push(`└─ Local changes: None (spec.md unchanged)`);
		}
	} else {
		lines.push(`└─ Not synced to Linear yet - run /spec linear sync-feature`);
	}

	if (status.taskSyncStatus.length > 0) {
		lines.push(`\nTasks (${status.taskSyncStatus.length} total):`);
		for (const task of status.taskSyncStatus) {
			if (task.hasSubIssue) {
				const icon = task.needsSync ? "⚠️" : "✅";
				const syncInfo = task.needsSync ? "needs sync" : "synced";
				lines.push(`├─ ${task.taskId}: ${task.subIssueKey} ${icon} ${syncInfo}`);
			} else {
				lines.push(`├─ ${task.taskId}: ❌ Not synced yet`);
			}
		}
	}

	if (status.duplicateTaskIds.length > 0) {
		lines.push(`\n⚠️ Duplicate task IDs: ${status.duplicateTaskIds.join(", ")}`);
	}

	if (status.newTasks.length > 0) {
		lines.push(`\n📝 New tasks (not yet synced): ${status.newTasks.join(", ")}`);
	}

	if (status.hasLinearIssue && (status.issueNeedsSync || status.newTasks.length > 0)) {
		lines.push(`\nNext action: Run /spec linear sync-feature or /spec linear sync-tasks`);
	}

	return lines.join("\n");
}

