	/**
	 * Show Linear sync status for current feature
	 */
	async showStatus(): Promise<void> {
		if (!this.paths.featureDir || !this.paths.tasksFile) {
			throw new LinearSyncError(
				"No active feature found",
				"NO_ACTIVE_FEATURE",
				undefined,
				false,
			);
		}

		// Load metadata
		const metadata = await loadMetadata(this.paths.featureDir);

		// Build task sync status
		const taskSyncStatus = [];
		let issueNeedsSync = false;

		if (metadata) {
			// Parse tasks.md to get current state
			try {
				const tasks = await parseTasks(this.paths.tasksFile);

				// Build status for each task
				for (const task of tasks) {
					const meta = metadata.tasks.find((t) => t.taskId === task.id);
					const needsSync =
						!meta ||
						meta.taskHash !== computeHash(task.rawContent) ||
						meta.isComplete !== task.isComplete;

					taskSyncStatus.push({
						taskId: task.id,
						hasSubIssue: !!meta,
						subIssueKey: meta?.linearSubIssueKey || null,
						needsSync,
						completionChanged: meta ? meta.isComplete !== task.isComplete : false,
						lastSync: meta?.lastSync || null,
					});
				}
			} catch (error) {
				this.ctx.ui.notify(
					`Failed to parse tasks.md: ${(error as Error).message}`,
					"warning",
				);
			}

			// Check if spec.md needs sync
			if (metadata.linear && this.paths.featureSpec) {
				try {
					const specContent = await readFile(this.paths.featureSpec, "utf-8");
					const currentHash = computeHash(specContent);
					issueNeedsSync = metadata.linear.specHash !== currentHash;
				} catch (error) {
					// Ignore spec read errors for status
				}
			}
		}

		// Build status object
		const status = buildSyncStatus(
			this.paths.featureDir.split("/").pop()!,
			!!metadata?.linear,
			metadata?.linear?.issueKey || null,
			taskSyncStatus,
		);
		status.issueNeedsSync = issueNeedsSync;
		status.lastIssueSync = metadata?.linear?.lastSync || null;

		// Format and display
		this.ctx.ui.notify(formatSyncStatus(status), "info");
	}
}

