/**
 * Invoke Linear API via @fink-andreas/pi-linear-tools extension
 * Uses pi.sendUserMessage() to queue tool invocation through the agent
 */
private async invokeLinearTool(params: Record<string, unknown>): Promise<any> {
	// Build a prompt that asks the agent to call the linear_issue tool
	const promptParts = [
		"Please call the linear_issue tool with these exact parameters:",
		"```json",
		JSON.stringify(params, null, 2),
		"```",
		"Return only the tool result without any additional commentary.",
	];

	const prompt = promptParts.join("\n");

	// Queue the tool invocation through the agent
	this.pi.sendUserMessage(prompt);

	// NOTE: This is async - the tool won't be called immediately
	// This is a limitation of the extension architecture
	// The user will see the agent call the tool and can observe the result
	throw new LinearSyncError(
		"Linear sync queued - watch for the agent to call linear_issue tool.\n" +
			"Note: The current pi extension API doesn't support synchronous tool invocation from commands.\n" +
			"The sync will complete when the agent finishes the tool call.",
		"ASYNC_OPERATION",
		undefined,
		true,
	);
}

