// Process each task
for (const task of tasks) {
	// Find existing metadata for this task
	const existingMeta = metadata.tasks.find((t) => t.taskId === task.id);

	// Compute task hash for change detection
	const currentHash = computeHash(task.rawContent);

	// Check if task has changed
	const hasChanged = !existingMeta || existingMeta.taskHash !== currentHash;
	const completionChanged = !existingMeta || existingMeta.isComplete !== task.isComplete;

	if (!hasChanged && !completionChanged) {
		// Skip unchanged tasks
		continue;
	}

	// Sanitize task content
	const { sanitized } = sanitizeContent(task.description, this.paths.repoRoot);
	const taskTitle = `${task.id} - ${task.title}`;

	try {
		if (existingMeta) {
			// Update existing Sub-Issue
			const updateParams: Record<string, unknown> = {
				action: "update",
				issue: existingMeta.linearSubIssueKey,
			};

			if (hasChanged) {
				updateParams.description = sanitized;
			}

			const result = await linearTool.invoke(updateParams);

			if (!result.success) {
				throw new Error(result.error?.message || "Update failed");
			}

			// Update metadata
			existingMeta.taskHash = currentHash;
			existingMeta.lastSync = new Date().toISOString();
			existingMeta.isComplete = task.isComplete;

			syncedKeys.push(existingMeta.linearSubIssueKey);
			this.ctx.ui.notify(`Updated ${task.id} → ${existingMeta.linearSubIssueKey}`, "info");
		} else {
			// Create new Sub-Issue
			const result = await linearTool.invoke({
				action: "create",
				title: taskTitle,
				description: sanitized,
				parentId: metadata.linear.issueId,
				team: metadata.linear.teamKey,
			});

			if (!result.success) {
				throw new Error(result.error?.message || "Create failed");
			}

			// Add to metadata
			metadata.tasks.push({
				taskId: task.id,
				linearSubIssueId: result.issue.id,
				linearSubIssueKey: result.issue.identifier,
				lastSync: new Date().toISOString(),
				taskHash: currentHash,
				isComplete: task.isComplete,
			});

			syncedKeys.push(result.issue.identifier);
			this.ctx.ui.notify(`Created ${task.id} → ${result.issue.identifier}`, "info");
		}

		// Check if Sub-Issue should transition to "Closed - Done"
		if (existingMeta && StatusTransitionManager.shouldTransitionSubIssue(task, existingMeta)) {
			await this.transitionSubIssueStatus(existingMeta.linearSubIssueKey);
		}
	} catch (error) {
		this.ctx.ui.notify(
			`Failed to sync ${task.id}: ${(error as Error).message}`,
			"warning",
		);
		// Continue with other tasks
	}
}

// Save metadata before transitioning parent Issue
await writeMetadata(this.paths.featureDir, metadata);

