private async getCurrentIssueState(
	issueKey: string,
): Promise<{ name: string; type: string } | null> {
	const linearTool = await this.getLinearTool();

	try {
		const result = await linearTool.invoke({
			action: "view",
			issue: issueKey,
		});

		if (!result.success || !result.issue?.state) {
			return null;
		}

		return {
			name: result.issue.state.name,
			type: result.issue.state.type,
		};
	} catch (error) {
		// Log but don't fail the whole sync
		console.warn(`Failed to get Issue state: ${(error as Error).message}`);
		return null;
	}
}

/**
 * Transition a Sub-Issue status to "Closed - Done"
 * @param subIssueKey - Linear Sub-Issue key
 */
private async transitionSubIssueStatus(subIssueKey: string): Promise<void> {
	const linearTool = await this.getLinearTool();

	try {
		const result = await linearTool.invoke({
			action: "update",
			issue: subIssueKey,
			state: STATUS_TRANSITION_RULES.subIssue.onTaskComplete,
		});

		if (!result.success) {
			throw new Error(result.error?.message || "Status transition failed");
		}

		this.ctx.ui.notify(
			`${subIssueKey} → ${STATUS_TRANSITION_RULES.subIssue.onTaskComplete}`,
			"info",
		);
	} catch (error) {
		// Log but don't fail the whole sync
		this.ctx.ui.notify(
			`Failed to transition ${subIssueKey}: ${(error as Error).message}`,
			"warning",
		);
	}
}

/**
 * Transition parent Issue to "In Progress" if appropriate
 * @param issueKey - Linear Issue key
 * @param tasks - Current tasks from tasks.md
 */
private async transitionParentIssue(
	issueKey: string,
	tasks: import("./types.ts").ParsedTask[],
): Promise<void> {
	// Get current Issue state
	const currentState = await this.getCurrentIssueState(issueKey);

	if (!currentState) {
		// Couldn't get state, skip transition
		return;
	}

	// Check if we should transition
	if (!StatusTransitionManager.shouldTransitionParentIssue(tasks, currentState)) {
		return;
	}

	const linearTool = await this.getLinearTool();

	try {
		const result = await linearTool.invoke({
			action: "update",
			issue: issueKey,
			state: STATUS_TRANSITION_RULES.issue.onFirstTaskComplete,
		});

		if (!result.success) {
			throw new Error(result.error?.message || "Status transition failed");
		}

		this.ctx.ui.notify(
			`Parent Issue ${issueKey} → ${STATUS_TRANSITION_RULES.issue.onFirstTaskComplete}`,
			"info",
		);
	} catch (error) {
		// Log but don't fail the whole sync
		this.ctx.ui.notify(
			`Failed to transition parent Issue: ${(error as Error).message}`,
			"warning",
		);
	}
}

