import { readFile } from "node:fs/promises";
import { join } from "node:path";
import type { ExtensionAPI, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import type { LinearMetadata, WorkflowPaths } from "./types.ts";
import { LinearSyncError } from "./types.ts";
import {
	computeHash,
	createInitialMetadata,
	loadMetadata,
	writeMetadata,
} from "./linear-metadata.js";
import { formatSanitizationSummary, sanitizeContent } from "./linear-sanitizer.js";
import { findTaskById, parseTasks } from "./tasks-parser.js";
import {
	buildSyncStatus,
	formatSyncStatus,
	STATUS_TRANSITION_RULES,
	StatusTransitionManager,
} from "./linear-status.js";

/**
 * Linear integration coordinator for /spec extension
 */
export class LinearIntegration {
	constructor(
		private ctx: ExtensionCommandContext,
		private paths: WorkflowPaths,
		private pi: ExtensionAPI,
	) {}

	/**
	 * Queue Linear tool invocation via agent
	 * Uses pi.sendUserMessage() to prompt the agent to call linear_issue tool
	 */
	private queueLinearToolCall(params: Record<string, unknown>, description: string): void {
		// Build a prompt that asks the agent to call the linear_issue tool
		const promptParts = [
			`Task: ${description}`,
			"",
			"Please call the linear_issue tool with these exact parameters:",
			"```json",
			JSON.stringify(params, null, 2),
			"```",
			"",
			"After calling the tool, report the result (Issue key, URL, and status).",
		];

		const prompt = promptParts.join("\n");

		// Queue the tool invocation through the agent
		this.pi.sendUserMessage(prompt);
	}

	/**
	 * Prompt user for Linear team key
	 * @returns Team key (e.g., "SCH", "ENG")
	 */
	private async promptTeamKey(): Promise<string> {
		if (!this.ctx.hasUI || typeof this.ctx.ui.input !== "function") {
			throw new LinearSyncError(
				"Cannot prompt for team key - UI not available",
				"NO_UI",
				undefined,
				false,
			);
		}

		const response = await this.ctx.ui.input(
			"Enter your Linear team key (e.g., SCH, ENG, PROJ):",
			"",
		);

		const teamKey = response?.trim().toUpperCase();

		if (!teamKey || !/^[A-Z]{2,4}$/.test(teamKey)) {
			throw new LinearSyncError(
				"Invalid team key format. Must be 2-4 uppercase letters (e.g., SCH, ENG)",
				"INVALID_TEAM_KEY",
				{ input: response },
				false,
			);
		}

		return teamKey;
	}

	/**
	 * Sync feature spec.md to Linear Issue (create or update)
	 * @returns Linear Issue key (e.g., "SCH-1234")
	 */
	async syncFeature(): Promise<string> {
		if (!this.paths.featureDir || !this.paths.featureSpec) {
			throw new LinearSyncError(
				"No active feature found. Run /spec specify first.",
				"NO_ACTIVE_FEATURE",
				undefined,
				false,
			);
		}

		// Load spec.md
		let specContent: string;
		try {
			specContent = await readFile(this.paths.featureSpec, "utf-8");
		} catch (error) {
			throw new LinearSyncError(
				`Failed to read spec.md: ${(error as Error).message}`,
				"SPEC_READ_ERROR",
				error,
				false,
			);
		}

		// Compute hash for change detection
		const currentHash = computeHash(specContent);

		// Load or create metadata
		const metadata =
			(await loadMetadata(this.paths.featureDir)) ||
			createInitialMetadata(this.paths.featureDir.split("/").pop()!);

		// Check if spec has changed
		if (metadata.linear && metadata.linear.specHash === currentHash) {
			this.ctx.ui.notify(
				`ℹ️ No changes detected - spec.md unchanged since last sync (${metadata.linear.lastSync})\n` +
					`   Issue: ${metadata.linear.issueKey}\n` +
					`   No action needed.`,
				"info",
			);
			return metadata.linear.issueKey;
		}

		// Sanitize content
		const { sanitized, changes } = sanitizeContent(specContent, this.paths.repoRoot);
		const sanitizationSummary = formatSanitizationSummary(changes);

		// Extract title from spec.md (first # heading)
		const titleMatch = specContent.match(/^#\s+(.+)$/m);
		const title = titleMatch?.[1] || "Untitled Feature";

		// Get team key (from metadata or prompt user)
		const teamKey = metadata.linear?.teamKey || (await this.promptTeamKey());

		// Prepare Linear API parameters
		const isUpdate = !!metadata.linear;
		const apiParams = isUpdate
			? {
					action: "update",
					issue: metadata.linear.issueKey,
					description: sanitized,
				}
			: {
					action: "create",
					title,
					description: sanitized,
					team: teamKey,
				};

		const operation = isUpdate ? "update" : "create";
		const taskDescription = isUpdate
			? `Update Linear Issue ${metadata.linear.issueKey} with latest spec.md content`
			: `Create new Linear Issue in team ${teamKey} from spec.md`;

		// Display preparation info
		this.ctx.ui.notify(
			`📋 Preparing to ${operation} Linear Issue\n\n` +
				`Spec: ${this.paths.featureSpec}\n` +
				`Title: ${title}\n` +
				`Team: ${teamKey}\n` +
				`Sanitization: ${sanitizationSummary}\n\n` +
				`✅ Queued agent prompt to call linear_issue tool\n` +
				`👀 Watch the conversation for the tool call and result`,
			"info",
		);

		// Queue the Linear API call through the agent
		this.queueLinearToolCall(apiParams, taskDescription);

		// Return placeholder since operation is async
		return isUpdate ? metadata.linear.issueKey : "[queued]";
	}

	/**
	 * Sync tasks from tasks.md to Linear Sub-Issues
	 * @returns Array of synced Sub-Issue keys
	 */
	async syncTasks(): Promise<string[]> {
		if (!this.paths.featureDir || !this.paths.tasksFile) {
			throw new LinearSyncError(
				"No active feature or tasks file found",
				"NO_ACTIVE_FEATURE",
				undefined,
				false,
			);
		}

		// Load metadata
		const metadata = await loadMetadata(this.paths.featureDir);

		// Validate parent Issue exists
		if (!metadata || !metadata.linear) {
			throw new LinearSyncError(
				"Parent Issue not found. Run /spec linear sync-feature first.",
				"NO_PARENT_ISSUE",
				undefined,
				false,
			);
		}

		// Parse tasks.md
		const tasks = await parseTasks(this.paths.tasksFile);

		if (tasks.length === 0) {
			this.ctx.ui.notify("No tasks found in tasks.md", "info");
			return [];
		}

		this.ctx.ui.notify(`Found ${tasks.length} tasks to sync...`, "info");

		const linearTool = await this.getLinearTool();
		const syncedKeys: string[] = [];

		// Analyze which tasks need syncing
		const tasksToSync = tasks.filter((task) => {
			const existingMeta = metadata.tasks.find((t) => t.taskId === task.id);
			const currentHash = computeHash(task.rawContent);
			const hasChanged = !existingMeta || existingMeta.taskHash !== currentHash;
			const completionChanged = !existingMeta || existingMeta.isComplete !== task.isComplete;
			return hasChanged || completionChanged;
		});

		if (tasksToSync.length === 0) {
			this.ctx.ui.notify(
				`ℹ️ No changes detected - all tasks are up to date\n` +
					`   Parent Issue: ${metadata.linear.issueKey}\n` +
					`   ${tasks.length} task(s) already synced`,
				"info",
			);
			return [];
		}

		// Display preparation info
		this.ctx.ui.notify(
			`📋 Preparing to sync ${tasksToSync.length} task(s)\n\n` +
				`Parent Issue: ${metadata.linear.issueKey}\n` +
				`Total tasks: ${tasks.length}\n` +
				`Changed/new: ${tasksToSync.length}\n\n` +
				`✅ Queuing ${tasksToSync.length} agent prompt(s) to call linear_issue tool\n` +
				`👀 Watch the conversation for the tool calls and results`,
			"info",
		);

		// Queue each task sync through the agent
		for (const task of tasksToSync) {
			const existingMeta = metadata.tasks.find((t) => t.taskId === task.id);
			const { sanitized, changes } = sanitizeContent(task.description, this.paths.repoRoot);
			const taskTitle = `${task.id} - ${task.title}`;
			const isUpdate = !!existingMeta;

			const apiParams = isUpdate
				? {
						action: "update",
						issue: existingMeta.linearSubIssueKey,
						description: sanitized,
					}
				: {
						action: "create",
						title: taskTitle,
						description: sanitized,
						parentId: metadata.linear.issueId,
						team: metadata.linear.teamKey,
					};

			const operation = isUpdate ? "update" : "create";
			const targetKey = isUpdate ? existingMeta.linearSubIssueKey : "new Sub-Issue";
			const taskDescription = `${operation} ${targetKey} for ${task.id}: ${task.title}`;

			this.queueLinearToolCall(apiParams, taskDescription);

			// If task is marked complete, queue a status transition too
			if (task.isComplete && existingMeta && !existingMeta.isComplete) {
				const statusParams = {
					action: "update",
					issue: existingMeta.linearSubIssueKey,
					state: STATUS_TRANSITION_RULES.subIssue.onTaskComplete,
				};
				this.queueLinearToolCall(
					statusParams,
					`Transition ${existingMeta.linearSubIssueKey} to "${STATUS_TRANSITION_RULES.subIssue.onTaskComplete}"`,
				);
			}
		}

		// If any task is complete, queue parent Issue status transition
		const anyComplete = tasks.some((t) => t.isComplete);
		if (anyComplete) {
			const parentStatusParams = {
				action: "update",
				issue: metadata.linear.issueKey,
				state: STATUS_TRANSITION_RULES.issue.onFirstTaskComplete,
			};
			this.queueLinearToolCall(
				parentStatusParams,
				`Transition parent Issue ${metadata.linear.issueKey} to "${STATUS_TRANSITION_RULES.issue.onFirstTaskComplete}"`,
			);
		}

		// Return list of task IDs that were queued for sync
		return tasksToSync.map((t) => t.id);
	}

	/**
	 * Get current state of a Linear Issue
	 * @param issueKey - Linear Issue key
	 * @returns Issue state object or null if not found
	 */


	/**
	 * Show Linear sync status for current feature
	 * Compares local state with metadata (no Linear API calls)
	 */
	async showStatus(): Promise<void> {
		if (!this.paths.featureDir) {
			throw new LinearSyncError(
				"No active feature found",
				"NO_ACTIVE_FEATURE",
				undefined,
				false,
			);
		}

		const featureName = this.paths.featureDir.split("/").pop()!;

		// Load metadata
		const metadata = await loadMetadata(this.paths.featureDir);

		if (!metadata || !metadata.linear) {
			this.ctx.ui.notify(
				`📋 Linear Sync Status: ${featureName}\n\n` +
					`❌ Not synced to Linear yet\n\n` +
					`Run \`/spec linear sync-feature\` to create a Linear Issue`,
				"info",
			);
			return;
		}

		// Check if spec.md needs sync
		let specNeedsSync = false;
		let specInfo = "";
		if (this.paths.featureSpec) {
			try {
				const specContent = await readFile(this.paths.featureSpec, "utf-8");
				const currentHash = computeHash(specContent);
				specNeedsSync = metadata.linear.specHash !== currentHash;
				specInfo = specNeedsSync
					? "⚠️  spec.md has changes (needs sync)"
					: "✅ spec.md up to date";
			} catch (error) {
				specInfo = "❓ spec.md not found";
			}
		}

		// Analyze tasks
		let taskInfo = "";
		let tasksNeedingSync = 0;
		if (this.paths.tasksFile) {
			try {
				const tasks = await parseTasks(this.paths.tasksFile);
				const taskDetails: string[] = [];

				for (const task of tasks) {
					const meta = metadata.tasks.find((t) => t.taskId === task.id);
					const currentHash = computeHash(task.rawContent);
					const hasChanged = !meta || meta.taskHash !== currentHash;
					const completionChanged = meta && meta.isComplete !== task.isComplete;

					if (!meta) {
						taskDetails.push(`  • ${task.id}: ❌ Not synced yet`);
						tasksNeedingSync++;
					} else if (hasChanged || completionChanged) {
						const reason = completionChanged
							? "completion changed"
							: "content changed";
						taskDetails.push(
							`  • ${task.id}: ⚠️  ${meta.linearSubIssueKey} (${reason})`,
						);
						tasksNeedingSync++;
					} else {
						taskDetails.push(`  • ${task.id}: ✅ ${meta.linearSubIssueKey}`);
					}
				}

				taskInfo =
					`\nTasks (${tasks.length} total, ${tasksNeedingSync} need sync):\n` +
					taskDetails.join("\n");
			} catch (error) {
				taskInfo = `\n❓ Could not parse tasks.md: ${(error as Error).message}`;
			}
		}

		// Build and display status
		const statusMessage =
			`📋 Linear Sync Status: ${featureName}\n\n` +
			`Feature Issue: ${metadata.linear.issueKey}\n` +
			`Team: ${metadata.linear.teamKey}\n` +
			`Last synced: ${new Date(metadata.linear.lastSync).toLocaleString()}\n` +
			`Status: ${specInfo}` +
			taskInfo +
			(specNeedsSync || tasksNeedingSync > 0
				? `\n\n🔄 Next action: Run \`/spec linear sync-feature\` or \`/spec linear sync-tasks\``
				: `\n\n✅ Everything is up to date`);

		this.ctx.ui.notify(statusMessage, "info");
	}
}

/**
 * Sync feature spec.md to Linear Issue (standalone function for /spec linear sync-feature)
 */
export async function syncFeature(
	ctx: ExtensionCommandContext,
	paths: WorkflowPaths,
	pi: ExtensionAPI,
): Promise<void> {
	const integration = new LinearIntegration(ctx, paths, pi);
	try {
		await integration.syncFeature();
	} catch (error) {
		if (error instanceof LinearSyncError) {
			ctx.ui.notify(error.message, "error");
		} else {
			ctx.ui.notify(`Unexpected error: ${(error as Error).message}`, "error");
		}
		throw error;
	}
}

/**
 * Sync tasks to Linear Sub-Issues (standalone function for /spec linear sync-tasks)
 */
export async function syncTasks(
	ctx: ExtensionCommandContext,
	paths: WorkflowPaths,
	pi: ExtensionAPI,
): Promise<void> {
	const integration = new LinearIntegration(ctx, paths, pi);
